"""Blatter inverse modeling tools.

Provides classes for setting up and solving inverse problems using the
Blatter (higher-order) stress balance solver, analogous to the SSA
inverse tools in :mod:`PISM.invert.ssa`.
"""

import PISM
import PISM.invert.core
from PISM.logging import logMessage


# Map design variable names to Blatter forward problem constructors.
blatter_forward_problems = {
    'tauc': PISM.IP_BlatterTaucForwardProblem,
}


class BlatterForwardRun(PISM.ssa.SSARun):
    """Set up a Blatter forward problem for inversion.

    Analogous to :class:`PISM.invert.ssa.SSAForwardRun` but uses the
    Blatter solver instead of SSAFEM.

    Parameters
    ----------
    design_var : str
        Design variable name, currently only ``'tauc'``.
    Mz : int, optional
        Number of vertical levels in the Blatter sigma grid.
    coarsening_factor : int, optional
        Multigrid coarsening factor.
    """

    def __init__(self, design_var, Mz=11, coarsening_factor=2):
        PISM.ssa.SSARun.__init__(self)
        assert design_var in blatter_forward_problems
        self.grid = None
        self.config = PISM.Context().config
        self.design_var = design_var
        self.design_var_param = PISM.invert.core.createDesignVariableParam(
            self.config, self.design_var)
        self.is_regional = False
        self.Mz = Mz
        self.coarsening_factor = coarsening_factor

    def designVariable(self):
        """Return the name of the design variable."""
        return self.design_var

    def designVariableParameterization(self):
        """Return the zeta-to-design-variable parameterization object."""
        return self.design_var_param

    def _setFromOptions(self):
        """Read command-line options."""
        self.is_regional = PISM.OptionBool("-regional", "regional mode")

    def _constructSolver(self):
        """Return a Blatter forward problem instance instead of an SSA solver.

        Reads Mz and coarsening_factor from the PISM config so that
        ``-stress_balance.blatter.Mz`` and
        ``-stress_balance.blatter.coarsening_factor`` are respected.
        """
        Mz = int(self.config.get_number("stress_balance.blatter.Mz"))
        coarsening = int(self.config.get_number(
            "stress_balance.blatter.coarsening_factor"))
        return PISM.IP_BlatterTaucForwardProblem(
            self.grid, Mz, coarsening, self.design_var_param)

    def _initSolver(self):
        """Initialize the Blatter forward problem."""
        self.solver.init()

    def write(self, filename, append=False):
        """Write model vecs and the Blatter solution to an output file.

        Overrides :meth:`SSARun.write` to handle the Blatter solver's
        velocity accessor and available diagnostics.
        """
        from PISM import util, model

        vecs = self.modeldata.vecs

        # Don't call prepare_output here — the file was already created
        # by pismi_blatter.py. Just write variables to the existing file.

        # Get velocity from the Blatter solver
        vel = self.solver.velocity()
        vecs.add(vel)

        velbar_mag = model.createCBarVec(self.grid)
        PISM.compute_magnitude(vel, velbar_mag)
        PISM.apply_mask(vecs.land_ice_thickness,
                        util.convert(-0.01, "m/year", "m/second"),
                        velbar_mag)
        vecs.add(velbar_mag)

        # Write available diagnostics (taud, taud_mag exist on
        # ShallowStressBalance; nuH is SSA-only)
        diagnostics = self.solver.spatial_diagnostics()
        for name in ["taud", "taud_mag"]:
            if name in diagnostics:
                vecs.add(diagnostics[name].compute())
        for name in ["nuH"]:
            try:
                if name in diagnostics:
                    vecs.add(diagnostics[name].compute())
            except Exception:
                pass

        vecs.writeall(filename)


class BlatterForwardRunFromInputFile(BlatterForwardRun):
    """Blatter forward run initialized from a NetCDF input file.

    Analogous to :class:`PISM.invert.ssa.SSAForwardRunFromInputFile`.

    Parameters
    ----------
    input_filename : str
        Path to the NetCDF file with model state.
    inv_data_filename : str
        Path to the NetCDF file with inversion data (observed velocities).
    design_var : str
        Design variable name (``'tauc'``).
    Mz : int, optional
        Number of Blatter vertical levels.
    coarsening_factor : int, optional
        Multigrid coarsening factor.
    """

    def __init__(self, input_filename, inv_data_filename, design_var,
                 Mz=11, coarsening_factor=2):
        BlatterForwardRun.__init__(self, design_var, Mz, coarsening_factor)
        self.input_filename = input_filename
        self.inv_data_filename = inv_data_filename

    def _initGrid(self):
        """Initialize grid from the input file."""
        ctx = PISM.Context().ctx

        if self.is_regional:
            ctx.config().set_string("grid.registration", "corner")
        else:
            ctx.config().set_string("grid.registration", "center")

        self.grid = PISM.Grid.FromOptions(ctx)

    def _initPhysics(self):
        """Set physics from command-line flags."""
        config = self.config
        enthalpyconverter = PISM.EnthalpyConverter(config)
        self.modeldata.setPhysics(enthalpyconverter)

    def _initCoefficients(self):
        """Read SSA coefficients from the input file."""
        self._allocStdSSACoefficients()

        vecs = self.modeldata.vecs
        thickness = vecs.land_ice_thickness
        bed = vecs.bedrock_altitude
        enthalpy = vecs.enthalpy
        mask = vecs.mask
        surface = vecs.surface_altitude
        sea_level = vecs.sea_level

        sea_level.set(0.0)

        # Honor `-input.regrid.file` / `-input.regrid.vars` for fields that
        # don't live in the bootstrap file (notably 3D enthalpy). The main
        # PISM run consumes these config keys via C++; this Python driver
        # has to do it explicitly.
        regrid_filename = self.config.get_string("input.regrid.file")
        regrid_vars = set(filter(
            None, self.config.get_string("input.regrid.vars").split(",")))

        def regrid(v, critical=True):
            name = v.metadata().get_string("short_name")
            if regrid_filename and name in regrid_vars:
                v.regrid(regrid_filename, critical)
            else:
                v.regrid(self.input_filename, critical)

        for v in [thickness, bed, enthalpy]:
            regrid(v)

        gc = PISM.GeometryCalculator(self.config)
        gc.compute(sea_level, bed, thickness, mask, surface)

        # Compute or read tauc
        if PISM.util.fileHasVariable(self.input_filename, 'tauc'):
            vecs.tauc.regrid(self.input_filename, critical=True)

        # Read observed velocities if available
        if PISM.util.fileHasVariable(self.inv_data_filename,
                                     'vel_misfit_weight'):
            vecs.add(PISM.model.createVelocityMisfitWeightVec(self.grid))
            vecs.vel_misfit_weight.regrid(self.inv_data_filename, True)

        # Dirichlet BCs
        if self.config.get_flag('stress_balance.ssa.dirichlet_bc'):
            vecs.add(PISM.model.create2dVelocityVec(
                self.grid, name='_bc',
                desc='velocity boundary condition'), "vel_bc")
            has_u_bc = PISM.util.fileHasVariable(self.input_filename, 'u_bc')
            has_v_bc = PISM.util.fileHasVariable(self.input_filename, 'v_bc')
            if (not has_u_bc) or (not has_v_bc):
                vecs.vel_bc.set(0.0)
            else:
                vecs.vel_bc.regrid(self.input_filename, True)

            vecs.add(PISM.model.createBCMaskVec(self.grid), 'vel_bc_mask')
            bc_mask_name = vecs.vel_bc_mask.metadata().get_string("short_name")
            if PISM.util.fileHasVariable(self.input_filename, bc_mask_name):
                vecs.vel_bc_mask.regrid(self.input_filename, True)
            else:
                vecs.vel_bc_mask.set(0)


def createInvBlatterSolver(blatterrun, method=None):
    """Factory function returning an inverse solver for the Blatter forward problem.

    Parameters
    ----------
    blatterrun : BlatterForwardRun
        The forward problem setup.
    method : str, optional
        Inversion method. Defaults to config ``inverse.stress_balance.method``.

    Returns
    -------
    InvSSASolver
        The inverse solver instance.
    """
    if method is None:
        method = blatterrun.config.get_string('inverse.stress_balance.method')

    if method.startswith('tikhonov'):
        from PISM.invert.blatter_tao import InvBlatterSolver_Tikhonov
        return InvBlatterSolver_Tikhonov(blatterrun, method)

    raise RuntimeError(
        "Unknown or unsupported inverse method '%s' for Blatter."
        " Supported: tikhonov_lmvm, tikhonov_cg, tikhonov_blmvm" % method)
